import { generateObject } from 'ai';
import { vexMiddleware } from '@vex_dev/sdk';

const vex = vexMiddleware({
  projectId: 'your-project-id',
  rules: ['pci-compliance', 'refund-accuracy']
});

type CheckoutInfo = { price: number; policy: string };

export async function getCheckoutInfo(cartId: string) {
  const { object } = await generateObject({
    model: 'gpt-4o-mini',
    schema: z.object({
      price: z.number(),
      policy: z.string()
    }),
    prompt: `Checkout info for cart ${cartId}`,
    ...vex.middleware()
  }) as CheckoutInfo;
  return object;
}
